def sanitize_headers(headers):
    """Remove sensitive information from headers"""
    sensitive_headers = ['authorization', 'x-api-key', 'cookie', 'x-auth-token']
    sanitized = {}
    for key, value in headers.items():
        if key.lower() in sensitive_headers:
            sanitized[key] = '[REDACTED]'
        else:
            sanitized[key] = value
    return sanitized


def sanitize_body(body_data):
    """Remove sensitive information from request/response body"""
    if not body_data:
        return body_data
    
    sensitive_fields = ['password', 'token', 'secret', 'api_key', 'apikey', 
                       'access_token', 'refresh_token', 'auth_token', 'credit_card',
                       'ssn', 'social_security', 'cvv', 'pin']
    
    if isinstance(body_data, dict):
        sanitized = {}
        for key, value in body_data.items():
            if any(sensitive in key.lower() for sensitive in sensitive_fields):
                sanitized[key] = '[REDACTED]'
            elif isinstance(value, dict):
                sanitized[key] = sanitize_body(value)
            elif isinstance(value, list):
                sanitized[key] = [sanitize_body(item) if isinstance(item, dict) else item for item in value]
            else:
                sanitized[key] = value
        return sanitized
    return body_data


